import { Component } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { Router } from '@angular/router';
import { AuthService } from '../services/auth.service';

@Component({
  selector: 'app-login',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './login.component.html',
  styleUrls: ['./login.component.scss']
})
export class LoginComponent {
  step: 'choice' | 'login' | 'welcome' = 'choice';
  selectedRole: string = '';
  userCredentials = { email: '', password: '' };

  constructor(private router: Router, private authService: AuthService) {}

  selectUserType(role: string) {
    this.selectedRole = role;
    this.step = 'login';
  }

  handleLogin() {
    this.authService.login(this.selectedRole, this.userCredentials.email, this.userCredentials.password)
      .subscribe({
        next: (res) => {
          this.authService.storeSession(res.token, res.role);
          this.step = 'welcome';
        },
        error: (err) => {
          alert(err.error?.message || 'Email or password is incorrect');
          this.userCredentials.password = '';
        }
      });
  }

  onGetStarted() {
    const role = this.authService.getRole();
    if (role === 'Admin') {
      this.router.navigate(['/dashboard']);
    } else {
      this.router.navigate(['/doctor']);
    }
  }

  goBack() {
    this.step = 'choice';
    this.userCredentials = { email: '', password: '' };
  }
}
